#!/usr/bin/env python3
"""Generate 250 unique Chinese idioms not already in idioms.json and write to idioms_extra.json."""

import json

# Load existing names
with open('/workspace/backend/src/data/idioms.json', 'r', encoding='utf-8') as f:
    existing = json.load(f)
existing_names = set(item['name'] for item in existing)
print(f"Existing idioms count: {len(existing_names)}")

# Define all idioms
idioms = []

def add(name, pinyin, category, difficulty, meaning, source, examples, synonyms, antonyms):
    if name not in existing_names:
        idioms.append((name, pinyin, category, difficulty, meaning, source, examples, synonyms, antonyms))

